const input = $input.first().json;

// Récupération du numéro (plus lisible + évite répétition)
const rawNumero = input.body?.phone_number || input.phone_number || '';

// Normalisation au format E.164 (France)
let normalized = rawNumero.replace(/[^0-9+]/g, '');

if (normalized.startsWith('0')) {
  normalized = '+33' + normalized.slice(1);
} else if (!normalized.startsWith('+')) {
  normalized = '+33' + normalized;
}

// Résultat
return [
  {
    json: {
      numero_client: normalized,
      poste_assistante: 'SIP/100',
      contact_name: input.contact_name || 'Client',
      hubspot_contact_id: input.contact_id || '',
    },
  },
];

const net = require('net');

const AMI_HOST = 'YOUR_FREEPBX_HOST';
const AMI_PORT = 5038;
const AMI_USER = 'YOUR_AMI_USERNAME';
const AMI_PASS = 'YOUR_AMI_PASSWORD';

const { numero_client: numero, poste_assistante: poste, contact_name: nom } =
  $input.first().json;

return new Promise((resolve, reject) => {
  const client = new net.Socket();

  let buffer = '';
  let loggedIn = false;

  // Connexion au serveur AMI
  client.connect(AMI_PORT, AMI_HOST, () => {
    const loginAction =
      `Action: Login\r\n` +
      `Username: ${AMI_USER}\r\n` +
      `Secret: ${AMI_PASS}\r\n\r\n`;

    client.write(loginAction);
  });

  client.on('data', (data) => {
    buffer += data.toString();

    // Authentification OK → lancer l'appel
    if (!loggedIn && buffer.includes('Authentication accepted')) {
      loggedIn = true;

      const originateAction =
        `Action: Originate\r\n` +
        `Channel: ${poste}\r\n` +
        `Exten: ${numero}\r\n` +
        `Context: from-internal\r\n` +
        `Priority: 1\r\n` +
        `CallerID: ${nom} <${numero}>\r\n` +
        `Timeout: 30000\r\n` +
        `Async: true\r\n\r\n`;

      client.write(originateAction);
    }

    // Succès → on ferme proprement
    if (loggedIn && buffer.includes('Response: Success')) {
      client.write('Action: Logoff\r\n\r\n');
      client.destroy();

      resolve([
        {
          json: {
            success: true,
            numero,
            poste,
          },
        },
      ]);
    }

    // Erreur AMI
    if (buffer.includes('Response: Error')) {
      client.destroy();
      reject(new Error(`AMI Originate failed: ${buffer}`));
    }
  });

  client.on('error', (err) => {
    client.destroy();
    reject(err);
  });

  // Timeout sécurité
  setTimeout(() => {
    client.destroy();
    reject(new Error('AMI timeout'));
  }, 10000);
});
